import { Routes } from '@angular/router';
import { authGuard } from './core/guards/auth.guard';
import { roleGuard } from './core/guards/role.guard';
import { LayoutComponent } from './shared/layout.component';

const ADMIN = { roles: ['admin'] as const };

/**
 * CodeDeck route tree. Hash routing is configured in app.config.ts.
 * `/login` + `/signup` render standalone; everything else is wrapped by
 * LayoutComponent and guarded by `authGuard`. Admin areas (users + settings)
 * additionally carry a `roleGuard` reading `data.roles`.
 * Each route carries `data.flow.node` for the flow map. The editor restores
 * deep-link state from `?file=<nodeId>&panel=search|history&q=<term>&rev=<revId>`.
 */
export const routes: Routes = [
  {
    path: 'login',
    loadComponent: () => import('./pages/login/login.component').then((m) => m.LoginComponent),
    data: { flow: { node: 'login', entry: true, edgesTo: ['workspaces', 'signup'] } },
  },
  {
    path: 'signup',
    loadComponent: () => import('./pages/signup/signup.component').then((m) => m.SignupComponent),
    data: { flow: { node: 'signup', edgesTo: ['workspaces', 'login'] } },
  },
  {
    path: '',
    component: LayoutComponent,
    canActivate: [authGuard],
    children: [
      // ---- Workspaces list (default) ----
      {
        path: '',
        pathMatch: 'full',
        canActivate: [authGuard],
        loadComponent: () =>
          import('./pages/workspaces-list/workspaces-list.component').then(
            (m) => m.WorkspacesListComponent,
          ),
        data: {
          flow: { node: 'workspaces', showInNavbar: true, edgesTo: ['workspace-editor'] },
        },
      },

      // ---- Workspace editor (file tree + tabs + editor + panels) ----
      {
        path: 'workspaces/:id',
        canActivate: [authGuard],
        loadComponent: () =>
          import('./pages/workspace-editor/workspace-editor.component').then(
            (m) => m.WorkspaceEditorComponent,
          ),
        data: { flow: { node: 'workspace-editor', edgesTo: ['workspaces'] } },
      },

      // ---- Admin: user management (admin only) ----
      {
        path: 'admin/users',
        canActivate: [authGuard, roleGuard],
        loadComponent: () =>
          import('./pages/admin-users/admin-users.component').then((m) => m.AdminUsersComponent),
        data: {
          roles: ADMIN.roles,
          flow: { node: 'admin-users', showInNavbar: true, scope: 'admin', edgesTo: ['workspaces'] },
        },
      },

      // ---- Admin: settings (admin only) ----
      {
        path: 'admin/settings',
        canActivate: [authGuard, roleGuard],
        loadComponent: () =>
          import('./pages/settings/settings.component').then((m) => m.SettingsComponent),
        data: {
          roles: ADMIN.roles,
          flow: { node: 'settings', showInNavbar: true, scope: 'admin', edgesTo: ['workspaces'] },
        },
      },
    ],
  },

  { path: '**', redirectTo: '' },
];
